FN = '"AR P教科書体M"'
TB = 'borders: left thin, right thin, top thin, bottom thin;'

def _e(font_str, align_str, border_str=TB, nf=None):
    s = f'font: name {FN}, {font_str}; alignment: {align_str}, vert centre; {border_str}'
    return xlwt.easyxf(s, num_format_str=nf or 'General')

