@app.route('/generate_excel', methods=['POST', 'OPTIONS'])
def generate_excel_endpoint():
    if request.method == 'OPTIONS':
        return '', 200
    try:
        d = request.get_json()
        xls_b64 = build_excel(d)
        xls_bytes = base64.b64decode(xls_b64)
        return send_file(
            io.BytesIO(xls_bytes),
            mimetype='application/vnd.ms-excel',
            as_attachment=True,
            download_name='mitsumori.xls'
        )
    except Exception as e:
        import traceback
        return jsonify({'error': str(e), 'trace': traceback.format_exc()}), 500

